<?php
if(!defined("IN_ESOTALK"))exit;class plugins extends Controller{var $view="plugins.view.php";var $plugins=array();function init(){if(!$this->esoTalk->user["admin"])redirect("");global $language,$config;$this->title=$language["Plugins"];if(isset($_FILES["installPlugin"]) and $this->esoTalk->validateToken(@$_POST["token"]))$this->installPlugin();if($handle=opendir("plugins")){while(false!==($file=readdir($handle))){if($file[0]!="." and is_dir("plugins/$file") and file_exists("plugins/$file/plugin.php") and (include_once "plugins/$file/plugin.php") and class_exists($file)){$plugin=new $file;$plugin->esoTalk=&$this->esoTalk;if(isset($_POST["saveSettings"]) and $_POST["plugin"]==$plugin->id and $this->esoTalk->validateToken($_POST["token"]))$plugin->saveSettings();$this->plugins[$plugin->id]=array("loaded"=>in_array($file,$config["loadedPlugins"]),"name"=>$plugin->name,"version"=>$plugin->version,"description"=>$plugin->description,"author"=>$plugin->author,"settings"=>$plugin->settings(),"plugin"=>$plugin);}}closedir($handle);}ksort($this->plugins);if(!empty($_GET["toggle"]) and $this->esoTalk->validateToken(@$_GET["token"]) and $this->togglePlugin($_POST["id"]))redirect("plugins");}function ajax(){global $config;switch($_POST["action"]){case "toggle":if(!$this->esoTalk->validateToken(@$_POST["token"]))return;$this->togglePlugin(@$_POST["id"]);}}function togglePlugin($plugin){if(!$plugin or !array_key_exists($plugin,$this->plugins))return false;global $config,$messages;$k=array_search($plugin,$config["loadedPlugins"]);if($k!==false)unset($config["loadedPlugins"][$k]);elseif($k===false){$config["loadedPlugins"][]=$plugin;if($msg=$this->plugins[$plugin]["plugin"]->enable()){$this->esoTalk->message("pluginCannotBeEnabled",false,array($this->plugins[$plugin]["name"],$messages[$msg]["message"]));return false;}}$config["loadedPlugins"]=array_unique($config["loadedPlugins"]);foreach($config["loadedPlugins"] as $k=>$v){if(!array_key_exists($v,$this->plugins))unset($config["loadedPlugins"][$k]);}if(!writeConfigFile("config/plugins.php",'$config["loadedPlugins"]',array_values((array)$config["loadedPlugins"]))){$this->esoTalk->message("notWritable",false,"config/plugins.php");return false;}return true;}function installPlugin(){if($_FILES["installPlugin"]["error"]){$this->esoTalk->message("invalidPlugin");return false;}if(!move_uploaded_file($_FILES["installPlugin"]["tmp_name"],"plugins/{$_FILES["installPlugin"]["name"]}")){$this->esoTalk->message("notWritable",false,"plugins/");return false;}if(!($files=unzip("plugins/{$_FILES["installPlugin"]["name"]}","plugins/")))$this->esoTalk->message("invalidPlugin");else {$directories=0;$pluginFound=false;foreach($files as $k=>$file){if(substr($file["name"],0,9)=="__MACOSX/" or substr($file["name"],-9)==".DS_Store"){unset($files[$k]);continue;}if($file["directory"] and substr_count($file["name"],"/")<2)$directories++;if(substr($file["name"],-10)=="plugin.php")$pluginFound=true;}if($pluginFound and $directories==1){$error=false;foreach($files as $k=>$file){if($file["directory"] and !is_dir("plugins/{$file["name"]}"))mkdir("plugins/{$file["name"]}");elseif(!$file["directory"]){if(!writeFile("plugins/{$file["name"]}",$file["content"])){$this->esoTalk->message("notWritable",false,"plugins/{$file["name"]}");$error=true;break;}}}if(!$error)$this->esoTalk->message("pluginAdded");}else $this->esoTalk->message("invalidPlugin");}unlink("plugins/{$_FILES["installPlugin"]["name"]}");}}?>
